generated_oml:
// C2: Acting Components – Physical actuators
instance PermanentMagnetSynchronousMotor : DTDFVocab:ActingComponent [
    base:desc "Primary motor of the first rotary axis; permanent–magnet synchronous motor."
]

instance GearTransmissionGearbox : DTDFVocab:ActingComponent [
    base:desc "Gear transmission that transmits motor torque to the axis carriage."
]

instance CycloidalGearbox : DTDFVocab:ActingComponent [
    base:desc "Cycloidal gearbox used in the MNABI MAX 100 rotary axis."
]

// C3: Physical sensing components
instance CurrentSensor : DTDFVocab:SensingComponent [
    base:desc "Excitation current sensor on the permanent–magnet synchronous motor (I_M)."
    DTDFVocab:producedData I_M_DataTransmission
]

instance MotorSideEncoder : DTDFVocab:SensingComponent [
    base:desc "Motor–side encoder that provides the motor angular position."
    DTDFVocab:producedData MotorSidePositionDataTransmission
]

instance GearboxSideEncoder : DTDFVocab:SensingComponent [
    base:desc "Gearbox–side encoder that provides the gearbox angular position."
    DTDFVocab:producedData GearboxSidePositionDataTransmission
]

// C4: Physical-to-virtual data transmission
instance I_M_DataTransmission : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom CurrentSensor
]

instance MotorSidePositionDataTransmission : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorSideEncoder
]

instance GearboxSidePositionDataTransmission : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom GearboxSideEncoder
]

// C10: Models/Data – Structural, simulation, and data calculation
instance StructuralSysMLModel : DTDFVocab:Model [
    base:desc "SysML structural model of the rotary axis assembly."
    DTDFVocab:inputTo AASEnabler
]

instance MotorDynamicsSimulinkModel : DTDFVocab:Model [
    base:desc "MATLAB/Simulink model of the permanent–magnet synchronous motor dynamics."
    DTDFVocab:inputTo SimulationRuntimeEnabler
]

instance GearwheelDynamicsSimulinkModel : DTDFVocab:Model [
    base:desc "MATLAB/Simulink model of the gearwheel dynamics including Coulomb–viscous friction."
    DTDFVocab:inputTo SimulationRuntimeEnabler
]

instance GearboxDynamicsSimulinkModel : DTDFVocab:Model [
    base:desc "MATLAB/Simulink model of the cycloidal gearbox dynamics with Stribeck, Dahl and LuGre friction."
    DTDFVocab:inputTo SimulationRuntimeEnabler
]

instance ReferenceTorqueCalculationModel : DTDFVocab:Model [
    base:desc "Data calculation model that computes reference torque from sensor data."
    DTDFVocab:inputTo SimulationRuntimeEnabler
]

instance ReferenceVelocityCalculationModel : DTDFVocab:Model [
    base:desc "Data calculation model that computes reference angular velocity from sensor data."
    DTDFVocab:inputTo SimulationRuntimeEnabler
]

// C10: Data instances – traces and processed data
instance MeasuredCurrentData : DTDFVocab:Data [
    base:desc "Measured current trace derived from I_M sensor data stream."
    DTDFVocab:inputTo MQTTBrokerEnabler
    DTDFVocab:fromData I_M_DataTransmission
]

instance MeasuredMotorPositionData : DTDFVocab:Data [
    base:desc "Measured motor position trace from motor–side encoder."
    DTDFVocab:inputTo MQTTBrokerEnabler
    DTDFVocab:fromData MotorSidePositionDataTransmission
]

instance MeasuredGearboxPositionData : DTDFVocab:Data [
    base:desc "Measured gearbox position trace from gearbox–side encoder."
    DTDFVocab:inputTo MQTTBrokerEnabler
    DTDFVocab:fromData GearboxSidePositionDataTransmission
]

instance ReferenceTorqueData : DTDFVocab:Data [
    base:desc "Computed reference torque trace from ReferenceTorqueCalculationModel."
    DTDFVocab:inputTo SimulationRuntimeEnabler
    DTDFVocab:fromData I_M_DataTransmission
]

instance ReferenceVelocityData : DTDFVocab:Data [
    base:desc "Computed reference angular velocity trace from ReferenceVelocityCalculationModel."
    DTDFVocab:inputTo SimulationRuntimeEnabler
    DTDFVocab:fromData I_M_DataTransmission
]

instance SimulatedMotorOutputData : DTDFVocab:Data [
    base:desc "Simulated motor output including friction effects from MotorDynamicsSimulinkModel."
    DTDFVocab:inputTo SimulationRuntimeEnabler
    DTDFVocab:fromData I_M_DataTransmission
]

instance SimulatedGearboxOutputData : DTDFVocab:Data [
    base:desc "Simulated gearbox output including friction effects from GearboxDynamicsSimulinkModel."
    DTDFVocab:inputTo SimulationRuntimeEnabler
    DTDFVocab:fromData I_M_DataTransmission
]

instance AggregatedSystemOutputData : DTDFVocab:Data [
    base:desc "Aggregated system output combining simulated motor and gearbox dynamics."
    DTDFVocab:inputTo SimulationRuntimeEnabler
    DTDFVocab:fromData SimulatedMotorOutputData
]

// C11: Enablers – transport, linkage, simulation, and UI
instance MQTTBrokerEnabler : DTDFVocab:Enabler [
    base:desc "MQTT broker instance for continuous sensor data streams."
    DTDFVocab:enables RealTimeFrictionIdentificationService, ComparisonDynService, DataAggregationService
]

instance AASEnabler : DTDFVocab:Enabler [
    base:desc "Asset Administration Shell linking the digital twin to physical asset metadata."
    DTDFVocab:enables StructuralSysMLModel
]

instance SimulationRuntimeEnabler : DTDFVocab:Enabler [
    base:desc "MATLAB/Simulink execution environment for running dynamic and friction models."
    DTDFVocab:enables MotorDynamicsSimulinkModel, GearwheelDynamicsSimulinkModel, GearboxDynamicsSimulinkModel,
              ReferenceTorqueCalculationModel, ReferenceVelocityCalculationModel,
              ComparisonDynService, DataAggregationService
]

instance DashboardEnabler : DTDFVocab:Enabler [
    base:desc "Dashboard GUI for visualization of measured, reference, and simulated traces."
    DTDFVocab:enables VisualizationDashboardService
]

// C6: Services – analysis, comparison, aggregation, visualization
instance RealTimeFrictionIdentificationService : DTDFVocab:Service [
    base:desc "Real‑time friction identification within the gear train using sensor and simulated data."
    DTDFVocab:provides FrictionParametersInsight
]

instance ComparisonDynService : DTDFVocab:Service [
    base:desc "Comparison of simulated (ideal, friction‑free, and friction‑affected) vs. measured motor/gearbox dynamics."
    DTDFVocab:provides MotionAccuracyInsight, MaintenancePredictionInsight
]

instance DataAggregationService : DTDFVocab:Service [
    base:desc "Multi‑physics aware data aggregation of motor and gearbox states."
    DTDFVocab:provides AggregatedDataInsight
]

instance VisualizationDashboardService : DTDFVocab:Service [
    base:desc "Unified visualization dashboard displaying measured, reference, and simulated traces."
    DTDFVocab:provides DashboardVisualizationInsight
]

// C17: Insights
instance FrictionParametersInsight : DTDFVocab:Insight [
    base:desc "Extracted friction parameters for controller feedback and motion accuracy improvement."
]

instance MaintenancePredictionInsight : DTDFVocab:Insight [
    base:desc "Monitoring of friction trends to trigger preventive maintenance actions."
]

instance MotionAccuracyInsight : DTDFVocab:Insight [
    base:desc "Analysis of deviations between measured and simulated dynamics for controller tuning."
]

instance AggregatedDataInsight : DTDFVocab:Insight [
    base:desc "Aggregated system output insight aiding holistic performance assessment."
]

instance DashboardVisualizationInsight : DTDFVocab:Insight [
    base:desc "Composite visualization of all trace data for operator monitoring."
]

// C17: Actions
instance UpdateControllerAction : DTDFVocab:Action [
    base:desc "Automatic update of robot controller parameters based on identified friction parameters."
    DTDFVocab:IsAutomatic true
]

instance TriggerMaintenanceAction : DTDFVocab:Action [
    base:desc "Automatic triggering of maintenance procedure when friction exceeds thresholds."
    DTDFVocab:IsAutomatic false
]

// C17: Environment
instance RotaryAxisEnvironment : DTDFVocab:Environment [
    base:contains PermanentMagnetSynchronousMotor, GearTransmissionGearbox, CycloidalGearbox,
           CurrentSensor, MotorSideEncoder, GearboxSideEncoder
]

instance virtual_to_physical_interaction : DTDFVocab:VirtualToPhysical [
    base:desc "None—the digital shadow is a passive observation layer and does not issue commands or torque adjustments to the physical robot during operation."
]

instance twinning_time_scale : DTDFVocab:TimeScale [
    base:desc "Real‑time continuous data flow with no explicit latency requirement; data is sampled at the robot controller rate (typically in the millisecond range) and processed instantly by the DT; the twin synchronizes with the PT at every control loop cycle."
]

instance dt_constellation : DTDFVocab:Constellation [
    base:desc "A centrally deployed constellation composed of the asset (MABI first axis), its engineering models, simulation models, processing component, data traces, AAS interfaces, and the visualization dashboard, all orchestrated under a single digital shadow instance."
]

instance life_cycle_stages : DTDFVocab:EvolutionStage [
    base:desc "Design and modeling stage (creation of engineering–simulation models in SysML and Simulink), Deployment stage (runtime attachment of the shadow to the first axis via MQTT and AAS), and Operation/Upgrade stage (continuous friction parameter identification and model refinement during robot service)."
]

instance fidelity_and_validity_considerations : DTDFVocab:FidelityConsideration [
    base:desc "Fidelity is ensured by grounding simulation models in measured motor constants, gear ratios, and friction model parameters; validation is achieved by real‑time comparison of simulated torques/velocities against high‑resolution encoder and current measurements, with differences used to adapt the white‑box friction models; traceability of each data point to its source and processing model preserves validity."
]

instance dt_technical_connection : DTDFVocab:TechnicalConnection [
    base:desc "MQTT is used for real‑time transmission of sensor streams from the robot controller to the digital shadow; AAS provides semantic linkage between data traces and asset models; no explicit REST/TCP endpoints are specified."
]

instance standardization : DTDFVocab:Standardization [
    base:desc "Standard MBSE practices using SysML for model definition, Asset Administration Shell for digital twin semantics, and MQTT for data exchange; the use of white‑box analytical and black‑box data‑driven friction models follows industry‑standard practice but no specific ISO standard is cited."
]
